package com.example.enterprise.service;

import com.example.enterprise.domain.AppUser;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.AppUserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;
import java.util.UUID;

@Service
public class UserService {

    private final AppUserRepository userRepository;

    public UserService(AppUserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public AppUser createUser(String email, String displayName) {
        if (userRepository.existsByEmail(email)) {
            throw new IllegalArgumentException("Email already exists");
        }
        AppUser user = new AppUser();
        user.setExternalId(UUID.randomUUID().toString().replace("-", ""));
        user.setEmail(email);
        user.setDisplayName(displayName);
        user.setStatus(UserStatus.ACTIVE);
        return userRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> findByExternalId(String externalId) {
        return userRepository.findByExternalId(externalId);
    }

    @Transactional
    public AppUser disableUser(Long id) {
        AppUser user = userRepository.findById(id).orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setStatus(UserStatus.DISABLED);
        return userRepository.save(user);
    }
}

