package com.example.enterprise.service;

import com.example.enterprise.domain.AppUser;
import com.example.enterprise.domain.PaymentTransaction;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.repository.AppUserRepository;
import com.example.enterprise.repository.PaymentTransactionRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.UUID;

@Service
public class TransactionService {

    private final PaymentTransactionRepository transactionRepository;
    private final AppUserRepository userRepository;

    public TransactionService(PaymentTransactionRepository transactionRepository, AppUserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public PaymentTransaction createTransaction(Long userId, BigDecimal amount, String currency, String description) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));

        PaymentTransaction txn = new PaymentTransaction();
        txn.setReference(UUID.randomUUID().toString().replace("-", ""));
        txn.setUser(user);
        txn.setAmount(amount);
        txn.setCurrency(currency);
        txn.setDescription(description);
        txn.setStatus(TransactionStatus.PENDING);

        return transactionRepository.save(txn);
    }

    @Transactional
    public PaymentTransaction markCompleted(String reference) {
        PaymentTransaction txn = transactionRepository.findByReference(reference)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        txn.setStatus(TransactionStatus.COMPLETED);
        return transactionRepository.save(txn);
    }

    @Transactional
    public PaymentTransaction markFailed(String reference) {
        PaymentTransaction txn = transactionRepository.findByReference(reference)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        txn.setStatus(TransactionStatus.FAILED);
        return transactionRepository.save(txn);
    }
}

