package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateUserRequest;
import com.example.enterprise.domain.AppUser;
import com.example.enterprise.service.UserService;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public ResponseEntity<AppUser> create(@Valid @RequestBody CreateUserRequest request) {
        return ResponseEntity.ok(userService.createUser(request.getEmail(), request.getDisplayName()));
    }

    @GetMapping("/{externalId}")
    public ResponseEntity<AppUser> getByExternalId(@PathVariable String externalId) {
        return userService.findByExternalId(externalId)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }
}

