package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateTransactionRequest;
import com.example.enterprise.domain.PaymentTransaction;
import com.example.enterprise.service.TransactionService;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping
    public ResponseEntity<PaymentTransaction> create(@Valid @RequestBody CreateTransactionRequest request) {
        return ResponseEntity.ok(
                transactionService.createTransaction(
                        request.getUserId(),
                        request.getAmount(),
                        request.getCurrency(),
                        request.getDescription()
                )
        );
    }

    @PostMapping("/{reference}/complete")
    public ResponseEntity<PaymentTransaction> complete(@PathVariable String reference) {
        return ResponseEntity.ok(transactionService.markCompleted(reference));
    }

    @PostMapping("/{reference}/fail")
    public ResponseEntity<PaymentTransaction> fail(@PathVariable String reference) {
        return ResponseEntity.ok(transactionService.markFailed(reference));
    }
}

